import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button, LabelMoney, formatUTCToLocalDisplay, StatusBadge, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { ContractDto } from '../../../services/bh/models';
import { useVoucherListActions } from '../../../hooks/useVoucherListActions';
import { CatalogDocumentHistory } from '../../../components/catalog/CatalogDocumentHistory';
import { salesDocumentTypes } from '../../../config/documentHistoryClients';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'bh-hop-dong-detail';

const CREATE_FORM = 'create-sales-contract';

const HopDongDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const { canUpdate } = useVoucherListActions(CREATE_FORM);
  const [item, setItem] = useState<ContractDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [historyOpen, setHistoryOpen] = useState(false);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService
        .getContract(id)
        .then(d => {
          if (!cancelled) setItem(d);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải hợp đồng'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [id, dispatch]);

  if (loading) {
    return (
      <div className={erp.loading} data-testid={`${TEST_ID}-loading`}>
        Đang tải...
      </div>
    );
  }

  if (!item) {
    return (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <p>Không tìm thấy hợp đồng</p>
        <Button variant="secondary" onClick={() => navigate('/bh/hd')}>
          Quay lại
        </Button>
      </div>
    );
  }

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <h1 className={erp.title} data-testid={`${TEST_ID}-title`}>
          Hợp đồng {item.code}
        </h1>
        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <StatusBadge status={item.status} />
          {canUpdate ? (
            <Button
              variant="primary"
              size="sm"
              onClick={() => navigate(`/bh/hd/${item.id}/sua`)}
              data-testid={`${TEST_ID}-edit-btn`}
            >
              Sửa
            </Button>
          ) : null}
          <Button
            variant="secondary"
            size="sm"
            onClick={() => setHistoryOpen(true)}
            data-testid={`${TEST_ID}-history-btn`}
          >
            <i className="fas fa-history" /> Lịch sử
          </Button>
          <Button
            variant="secondary"
            onClick={() => navigate('/bh/hd')}
            data-testid={`${TEST_ID}-back`}
          >
            Quay lại
          </Button>
        </div>
      </div>
      <CatalogDocumentHistory
        testIdPrefix={TEST_ID}
        documentType={salesDocumentTypes.salesContract}
        documentId={item.id}
        documentCode={item.code}
        isOpen={historyOpen}
        onClose={() => setHistoryOpen(false)}
      />
      <div className={erp.formCard} data-testid={`${TEST_ID}-body`}>
        <p>
          <b>Khách hàng:</b> {item.customerName}
        </p>
        <p>
          <b>Ngày:</b> {formatUTCToLocalDisplay(item.contractDate, false)}
        </p>
        {item.startDate ? (
          <p>
            <b>Từ ngày:</b> {formatUTCToLocalDisplay(item.startDate, false)}
          </p>
        ) : null}
        {item.endDate ? (
          <p>
            <b>Đến ngày:</b> {formatUTCToLocalDisplay(item.endDate, false)}
          </p>
        ) : null}
        <p>
          <b>Giá trị:</b> <LabelMoney layout="value" variant="cell" value={item.totalAmount} />
        </p>
        <p>
          <b>Mô tả:</b> {item.description ?? '—'}
        </p>
      </div>
    </div>
  );
};

export default HopDongDetailPage;
